def findOrder(numCourses, prerequisites):
    adj = [[] for _ in range(numCourses)]; deg = [0] * numCourses
    for a, b in prerequisites: adj[b].append(a); deg[a] += 1
    q = collections.deque([i for i in range(numCourses) if deg[i] == 0]); res = []
    while q:
        u = q.popleft(); res.append(u)
        for v in adj[u]:
            deg[v] -= 1
            if deg[v] == 0: q.append(v)
    return res if len(res) == numCourses else []

